package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.Excluder;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class Gson_ExcluderTest {

  private Gson gson;

  @BeforeEach
  public void setUp() throws Exception {
    gson = new Gson();
  }

  @Test
  public void testExcluder_NotNull() {
    Excluder excluder = gson.excluder();
    assertNotNull(excluder, "Excluder should not be null");
  }

  @Test
  public void testExcluder_Consistency() throws Exception {
    Excluder firstCall = gson.excluder();
    Excluder secondCall = gson.excluder();
    assertSame(firstCall, secondCall, "Excluder instance should be consistent across calls");
  }

  @Test
  public void testExcluder_ReflectPrivateField() throws Exception {
    Field excluderField = Gson.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    Excluder excluderFromField = (Excluder) excluderField.get(gson);
    Excluder excluderFromMethod = gson.excluder();
    assertSame(excluderFromField, excluderFromMethod, "Excluder from field and method should be the same");
  }
}
